# ANTI-PATTERN: Unbounded memory growth with no eviction
class BatterMemoryAntiPattern:
    def __init__(self):
        self.all_deliveries = []  # Stores EVERY ball ever faced

    def process_ball(self, delivery: Dict):
        self.all_deliveries.append(delivery)  # Grows infinitely
        # Searching through 10,000 balls takes O(n) time every decision
        similar_balls = [d for d in self.all_deliveries 
                        if d["line"] == delivery["line"]]
        return self.decide_shot(similar_balls)


# BEST PRACTICE: Bounded memory with intelligent eviction
from collections import deque

class BatterMemoryBestPractice:
    def __init__(self, max_memory_balls: int = 100):
        self.recent_deliveries = deque(maxlen=max_memory_balls)
        self.statistics = {  # Summarized patterns, not raw data
            "vs_pace": {"avg_runs": 3.2, "dot_percentage": 0.35},
            "vs_spin": {"avg_runs": 2.1, "dot_percentage": 0.52}
        }

    def process_ball(self, delivery: Dict):
        self.recent_deliveries.append(delivery)  # Old entries auto-evicted

        # O(1) lookup using pre-computed statistics
        if delivery["type"] == "pace":
            historical_context = self.statistics["vs_pace"]
        else:
            historical_context = self.statistics["vs_spin"]

        return self.decide_shot(historical_context)

    def update_statistics(self):
        """Periodically compress recent memory into statistics"""
        recent_pace = [d for d in self.recent_deliveries if d["type"] == "pace"]
        if recent_pace:
            self.statistics["vs_pace"]["avg_runs"] = sum(
                d.get("runs", 0) for d in recent_pace
            ) / len(recent_pace)


# COMPARISON: Same task, vastly different memory efficiency
from timeit import timeit

anti_pattern = BatterMemoryAntiPattern()
best_pattern = BatterMemoryBestPractice()

# Simulate 1000 deliveries
for i in range(1000):
    test_delivery = {"line": "off", "length": "good", "type": "pace", "runs": 2}
    anti_pattern.process_ball(test_delivery)
    best_pattern.process_ball(test_delivery)

print(f"Anti-pattern memory objects: {len(anti_pattern.all_deliveries)} balls")
print(f"Best practice memory objects: {len(best_pattern.recent_deliveries)} balls (max)")
print(f"Anti-pattern lookup time: O(n) = O({len(anti_pattern.all_deliveries)})")
print(f"Best practice lookup time: O(1)")
